#include<bits/stdc++.h>
using namespace std;
int fail[1000010],flag[1000010],in[1000010],son[1000010][31],cnt[1000010],ans[1000010],tot=1;
int res[1000010];
void insert(string s,int id)
{
    int p=1,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        if(!son[p][x])
        {
            son[p][x]=++tot;
        }
        p=son[p][x];
    }
    if(!flag[p])
    {
        flag[p]=id;
    }
    cnt[id]=flag[p];
}
void getfail()
{
    for(int i=0;i<=26;i++)
    {
        son[0][i]=1;
    }
    queue<int> q;
    q.push(1);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=0;i<=26;i++)
        {
            if(son[t][i])
            {
                fail[son[t][i]]=son[fail[t]][i];
                in[son[fail[t]][i]]++;
                q.push(son[t][i]);
            }
            else
            {
                son[t][i]=son[fail[t]][i];
            }
        }
    }
}
void query(string s)
{
    int len=s.size();
    int p=1;
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        p=son[p][x];
        ans[p]++;
    }
}
void topo()
{
    queue<int> q;
    for(int i=1;i<=tot;i++)
    {
        if(in[i]==0)
        {
            q.push(i);
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        res[flag[t]]=ans[t];
        int v=fail[t];
        in[v]--;
        ans[v]+=ans[t];
        if(in[v]==0)
        {
            q.push(v);
        }
    }
}
string s[1000010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        cin>>s[i];
        insert(s[i],i);
    }
    string str="";
    for(int i=1;i<=n;i++)
    {
        str=str+(char)(1+'z')+s[i];
    }
    getfail();
    query(str);
    topo();
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",res[cnt[i]]);
    }
    return 0;
}
